import { AsyncStorage } from 'react-native';

const DATA_STORAGE_KEY = 'app_data';

export const saveData = async (key, value) => {
  try {
    await AsyncStorage.setItem(DATA_STORAGE_KEY, JSON.stringify({ [key]: value }));
  } catch (error) {
    console.error('Error saving data:', error);
  }
};

export const getData = async (key) => {
  try {
    const storageData = await AsyncStorage.getItem(DATA_STORAGE_KEY);
    if (storageData) {
      const parsedData = JSON.parse(storageData);
      return parsedData[key];
    }
  } catch (error) {
    console.error('Error getting data:', error);
  }
};

export const removeData = async (key) => {
  try {
    await AsyncStorage.removeItem(DATA_STORAGE_KEY);
  } catch (error) {
    console.error('Error removing data:', error);
  }
};